import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {The algorithm assigns a score to each unvisited node based on a combination of proximity to the current node and 
    the average distance to its nearest neighbors, selecting the node with the highest combined score to efficiently 
    balance travel distance and distribution coverage, or returns to the depot if all nodes have been visited.}
    """
    if len(unvisited_nodes) == 0:
        return depot_node

    # Evaluate each unvisited node based on proximity to the current node and average distance to its nearest neighbors
    best_node = None
    best_score = -float('inf')
    for node in unvisited_nodes:
        if node in truck_nodes:
            continue
        proximity_score = 1 / (1 + distance_matrix[current_node, node])
        neighbor_distances = [distance_matrix[node, other] for other in unvisited_nodes if other != node]
        if neighbor_distances:
            average_neighbor_distance = np.mean(neighbor_distances)
        else:
            average_neighbor_distance = float('inf')
        distribution_score = 1 / (1 + average_neighbor_distance)
        combined_score = proximity_score + distribution_score

        if combined_score > best_score:
            best_score = combined_score
            best_node = node

    if best_node is not None:
        return best_node

    return next_node
